private static ETGOTMSalesFormLetterController newETGOTMSalesFormLetterControllerFromTable(DocumentStatus _documentStatus)
{
    ETGOTMSalesFormLetterService instance = ETGOTMSalesFormLetterServiceFactory::newETGOTMSalesFormLetterFromStatus(_documentStatus);
    ClassName className = instance.GetType().Name;
    ETGOTMSalesFormLetterController controller = new ETGOTMSalesFormLetterController();

    controller.parmClassName(className);
    controller.parmMethodName(methodStr(ETGOTMSalesFormLetterService, processOperation));
    controller.parmExecutionMode(SysOperationExecutionMode::Synchronous);

    return controller;
}

